import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import L from "leaflet";

// Fix default marker icon issue
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl:
    "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png",
  iconUrl:
    "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png",
  shadowUrl:
    "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png",
});

const BusMap = () => {
  const [buses, setBuses] = useState([]);

  useEffect(() => {
    // WebSocket connection to FastAPI
    const ws = new WebSocket("ws://localhost:8000/ws/buses");

    ws.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        const busArray = Object.values(data);
        setBuses(busArray);
      } catch (err) {
        console.error("WebSocket data parse error:", err);
      }
    };

    ws.onclose = () => {
      console.log("WebSocket closed, reconnecting in 5s...");
      setTimeout(() => window.location.reload(), 5000);
    };

    return () => ws.close();
  }, []);

  return (
    <div style={{ height: "100vh", width: "100%" }}>
      <MapContainer
        center={[40.7128, -74.006]} // NYC center
        zoom={12}
        style={{ height: "100%", width: "100%" }}
      >
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          attribution="&copy; OpenStreetMap contributors"
        />

        {buses.map((bus) => (
          <Marker key={bus.id} position={[bus.lat, bus.lon]}>
            <Popup>
              🚌 <b>Bus {bus.id}</b> <br />
              Route: {bus.route} <br />
              Speed: {bus.speed.toFixed(1)} mph <br />
              Status: {bus.status}
            </Popup>
          </Marker>
        ))}
      </MapContainer>
    </div>
  );
};

export default BusMap;
